import com.pinterest.ktlint.ruleset.standard.StandardRule
import org.jetbrains.kotlin.com.intellij.lang.ASTNode
import org.jetbrains.kotlin.com.intellij.psi.PsiWhiteSpace

public class SpacingAroundRangeOperatorRule : StandardRule("range-spacing") {
    override fun beforeVisitChildNodes(
        node: ASTNode,
        autoCorrect: Boolean,
        emit: (offset: Int, errorMessage: String, canBeAutoCorrected: Boolean) -> Unit,
    ) {
        if (node.elementType == RANGE) {
            // Check if this is part of the "..<" operator
            val nodeAfterRange = node.nextSibling { true }
            val isRangeUntil = nodeAfterRange?.elementType == LT

            if (isRangeUntil) {
                // Handle "..<" operator - spacing should be same as ".." (no spaces)
                val prevLeaf = node.prevLeaf()
                val nextLeaf = nodeAfterRange.nextLeaf()
                when {
                    prevLeaf is PsiWhiteSpace && nextLeaf is PsiWhiteSpace -> {
                        emit(node.startOffset, "Unexpected spacing around \"..<\"", true)
                        if (autoCorrect) {
                            prevLeaf.node.treeParent.removeChild(prevLeaf.node)
                            autoRemoveWhitespaceBetween(node, nodeAfterRange)
                            nextLeaf.node.treeParent.removeChild(nextLeaf.node)
                        }
                    }
                    prevLeaf is PsiWhiteSpace -> {
                        emit(prevLeaf.node.startOffset, "Unexpected spacing before \"..<\"", true)
                        if (autoCorrect) {
                            prevLeaf.node.treeParent.removeChild(prevLeaf.node)
                            autoRemoveWhitespaceBetween(node, nodeAfterRange)
                        }
                    }
                    nextLeaf is PsiWhiteSpace -> {
                        emit(nextLeaf.node.startOffset, "Unexpected spacing after \"..<\"", true)
                        if (autoCorrect) {
                            autoRemoveWhitespaceBetween(node, nodeAfterRange)
                            nextLeaf.node.treeParent.removeChild(nextLeaf.node)
                        }
                    }
                }
            } else {
                // Handle regular ".." operator
                val prevLeaf = node.prevLeaf()
                val nextLeaf = node.nextLeaf()
                when {
                    prevLeaf is PsiWhiteSpace && nextLeaf is PsiWhiteSpace -> {
                        emit(node.startOffset, "Unexpected spacing around \"..\"", true)
                        if (autoCorrect) {
                            prevLeaf.node.treeParent.removeChild(prevLeaf.node)
                            nextLeaf.node.treeParent.removeChild(nextLeaf.node)
                        }
                    }
                    prevLeaf is PsiWhiteSpace -> {
                        emit(prevLeaf.node.startOffset, "Unexpected spacing before \"..\"", true)
                        if (autoCorrect) {
                            prevLeaf.node.treeParent.removeChild(prevLeaf.node)
                        }
                    }
                    nextLeaf is PsiWhiteSpace -> {
                        emit(nextLeaf.node.startOffset, "Unexpected spacing after \"..\"", true)
                        if (autoCorrect) {
                            nextLeaf.node.treeParent.removeChild(nextLeaf.node)
                        }
                    }
                }
            }
        }
    }

    /**
     * Remove any whitespace between the RANGE and LT tokens
     */
    private fun autoRemoveWhitespaceBetween(rangeNode: ASTNode, ltNode: ASTNode) {
        val nodesBetween = mutableListOf<ASTNode>()
        var current = rangeNode.treeNext
        while (current != null && current != ltNode) {
            if (current is PsiWhiteSpace) {
                nodesBetween.add(current)
            }
            current = current.treeNext
        }
        nodesBetween.forEach { it.node.treeParent.removeChild(it.node) }
    }
}"}

